// ─── AdminDashboard: sidebar, routing, top-level state

const { useState, useEffect } = React;
function AdminDashboard({ onLogout }) {
    const [products, setProducts] = useState([]);
    const [editingProduct, setEditingProduct] = useState(null);
    const [showModal, setShowModal] = useState(false);
    const [showReviewModal, setShowReviewModal] = useState(false);
    const [showConfirmModal, setShowConfirmModal] = useState(false);
    const [showSuccessModal, setShowSuccessModal] = useState(false);
    const [successData, setSuccessData] = useState({});
    const [confirmData, setConfirmData] = useState({});
    const [draftCount, setDraftCount] = useState(DraftService.getDraftCount());
    const [activeTab, setActiveTab] = useState('orders');
    const [categories, setCategories] = useState([]);
    const [inactivityWarning, setInactivityWarning] = useState(false);
    const session = AuthService.getSession();
    const INACTIVE_LIMIT = 60 * 60 * 1000; // 60 minutes
    const WARNING_AT = 50 * 60 * 1000;     // 50 minutes

    // Auto-logoff after 60 minutes inactivity
    useEffect(() => {
        let lastActivity = Date.now();
        const resetTimer = () => { lastActivity = Date.now(); setInactivityWarning(false); };
        const events = ['mousemove','keydown','click','scroll','touchstart'];
        events.forEach(e => window.addEventListener(e, resetTimer, { passive: true }));

        const checkInterval = setInterval(() => {
            const idle = Date.now() - lastActivity;
            if (idle >= INACTIVE_LIMIT) {
                clearInterval(checkInterval);
                // Log the auto-logoff
                fetch(AZURE_FUNCTION_URL, {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json', 'x-admin-email': session.email },
                    body: JSON.stringify({ action: 'log-action', logEntry: { action: 'auth.auto_logoff', detail: { reason: 'inactivity_timeout', lastActivity: new Date(lastActivity).toISOString() }, result: 'success' }})
                }).catch(() => {}).finally(() => {
                    AuthService.logout();
                    onLogout();
                });
            } else if (idle >= WARNING_AT) {
                setInactivityWarning(true);
            }
        }, 60000);

        // Log login
        fetch(AZURE_FUNCTION_URL, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json', 'x-admin-email': session.email },
            body: JSON.stringify({ action: 'log-action', logEntry: { action: 'auth.login', detail: { browser: navigator.userAgent.substring(0,80) }, result: 'success' }})
        }).catch(() => {});

        return () => {
            clearInterval(checkInterval);
            events.forEach(e => window.removeEventListener(e, resetTimer));
        };
    }, []);
    
    useEffect(() => {
        ProductService.loadProducts().then(function(prods) {
            setProducts(DraftService.applyDrafts(prods));
            var slugs = prods.map(function(p) { return p.category; }).filter(function(v, i, a) { return a.indexOf(v) === i; });
            fetch('./categories.json?v=' + Date.now()).then(function(r) { return r.ok ? r.json() : []; }).then(function(cats) {
                if (cats && cats.length > 0) {
                    setCategories(cats);
                } else {
                    // Fallback to product slugs only if categories.json is empty
                    setCategories(slugs.map(function(s) { return { slug: s, label: s.split('_').map(function(w) { return w.charAt(0).toUpperCase() + w.slice(1); }).join(' ') }; }));
                }
            }).catch(function() {
                setCategories(slugs.map(function(s) { return { slug: s, label: s.split('_').map(function(w) { return w.charAt(0).toUpperCase() + w.slice(1); }).join(' ') }; }));
            });
        }).catch(function(err) {
            console.error('Failed to load products:', err);
            setProducts([]);
        });
    }, []);

    // UI-only update — updates or inserts in local state, no API call
    // Used by rename, revert, and any operation that handles its own API call
    const handleCategoryUpdated = (slug, label) => {
        setCategories(prev => {
            const exists = prev.find(c => c.slug === slug);
            if (exists) return prev.map(c => c.slug === slug ? { ...c, label } : c);
            return [...prev, { slug, label }];
        });
    };

    const handleCategoryAdded = async (slug, label) => {
        // Update UI instantly
        setCategories(prev => {
            const exists = prev.find(c => c.slug === slug);
            if (exists) return prev.map(c => c.slug === slug ? { ...c, label } : c);
            return [...prev, { slug, label }];
        });
        // Sync to GitHub in background
        try {
            const res = await fetch(AZURE_FUNCTION_URL, {
                method: 'POST',
                headers: { 'Content-Type': 'application/json', 'x-admin-email': session.email },
                body: JSON.stringify({ action: 'add-category', slug, label })
            });
            const text = await res.text();
            if (!text) throw new Error('Empty response from server');
            const data = JSON.parse(text);
            if (!res.ok) {
                // Revert on failure
                setCategories(prev => prev.filter(c => c.slug !== slug));
                throw new Error(data.message || 'Failed to save category');
            }
        } catch(e) {
            // Revert on network error
            setCategories(prev => prev.filter(c => c.slug !== slug));
            throw e;
        }
    };

    const handleCategoryRemoved = (slug) => {
        setCategories(prev => prev.filter(function(c) { return c.slug !== slug; }));
    };
    
    const handleSave = (product) => {
        // Merge with existing product to preserve fields not in the form (e.g. imageUrl)
        const existing = products.find(function(p) { return p.id === product.id; });
        const merged = existing ? Object.assign({}, existing, product) : product;
        
        // Assign ID BEFORE saving draft so the draft has a proper ID
        let updated;
        if (existing) {
            updated = products.map(function(p) { return p.id === merged.id ? merged : p; });
        } else {
            merged.id = Math.max.apply(null, products.map(function(p) { return p.id; }).concat([0])) + 1;
            updated = [...products, merged];
        }
        
        // Save as draft with proper ID
        DraftService.saveDraft(merged);
        
        setProducts(updated);
        setDraftCount(DraftService.getDraftCount());
        setShowModal(false);
        setEditingProduct(null);
    };
    
    const handleDelete = (productId) => {
        if (confirm('Are you sure you want to delete this product?')) {
            // Mark as deleted in drafts
            DraftService.saveDraft({ id: productId, _deleted: true });
            
            const updated = products.filter(p => p.id !== productId);
            setProducts(updated);
            setDraftCount(DraftService.getDraftCount());
        }
    };
    
    const handleToggleStatus = (productId) => {
        const product = products.find(p => p.id === productId);
        const updated = { ...product, available: !product.available };
        DraftService.saveDraft(updated);
        
        setProducts(products.map(p => 
            p.id === productId ? updated : p
        ));
        setDraftCount(DraftService.getDraftCount());
    };
    
    const handlePublishAll = async () => {
        // Show custom confirmation modal
        setConfirmData({
            count: draftCount,
            updates: draftCount === 1 ? 'update' : 'updates'
        });
        setShowConfirmModal(true);
    };
    
    const handleConfirmPublish = async () => {
        setShowConfirmModal(false);
        
        try {
            // Show loading state
            const publishBtn = document.querySelector('.btn-publish-all');
            if (publishBtn) {
                publishBtn.disabled = true;
                publishBtn.textContent = '⏳ Publishing...';
            }
            
            // Apply all drafts to create final products array
            const drafts = DraftService.getDrafts();
            let finalProducts = [...products];
            
            // Apply all draft changes
            Object.values(drafts).forEach(draft => {
                if (draft._deleted) {
                    finalProducts = finalProducts.filter(p => p.id !== draft.id);
                } else {
                    const index = finalProducts.findIndex(p => p.id === draft.id);
                    const { _draftTimestamp, ...cleanDraft } = draft;
                    if (index >= 0) {
                        finalProducts[index] = cleanDraft;
                    } else {
                        finalProducts.push(cleanDraft);
                    }
                }
            });
            
            // Publish to GitHub via Azure Function
            const result = await ProductService.publishToGitHub(finalProducts, session.email);
            
            // Success!
            DraftService.clearAllDrafts();
            setDraftCount(0);
            
            // Show success modal
            setSuccessData({
                count: finalProducts.length,
                commitSha: (result.commitSha ? result.commitSha.substring(0, 7) : '')
            });
            setShowSuccessModal(true);
            
            // Reload products
            ProductService.loadProducts().then(setProducts);
            
        } catch (error) {
            console.error('Publish error:', error);
            
            // Fallback to manual download
            const fallback = confirm(
                '❌ Auto-publish failed.\n\n' +
                error.message + '\n\n' +
                'Would you like to download products.json manually instead?'
            );
            
            if (fallback) {
                // Apply drafts
                const drafts = DraftService.getDrafts();
                let finalProducts = [...products];
                
                Object.values(drafts).forEach(draft => {
                    if (draft._deleted) {
                        finalProducts = finalProducts.filter(p => p.id !== draft.id);
                    } else {
                        const index = finalProducts.findIndex(p => p.id === draft.id);
                        const { _draftTimestamp, ...cleanDraft } = draft;
                        if (index >= 0) {
                            finalProducts[index] = cleanDraft;
                        } else {
                            finalProducts.push(cleanDraft);
                        }
                    }
                });
                
                // Download manually
                await ProductService.saveProducts(finalProducts);
                DraftService.clearAllDrafts();
                setDraftCount(0);
            }
        } finally {
            // Reset button state
            const publishBtn = document.querySelector('.btn-publish-all');
            if (publishBtn) {
                publishBtn.disabled = false;
                publishBtn.textContent = '📥 Publish All';
            }
        }
    };
    
    const handleClearDrafts = () => {
        if (!confirm(`Clear all ${draftCount} unsaved changes? This cannot be undone.`)) return;
        
        DraftService.clearAllDrafts();
        setDraftCount(0);
        
        // Reload original products
        ProductService.loadProducts().then(setProducts);
    };
    
    const initials = (session.email || '').split('@')[0].split('.').map(p => p[0] ? p[0].toUpperCase() : '').join('').slice(0,2);
    const isSuperAdmin = session.role === 'superadmin';
    const sectionTitles = {
        access: 'Access Management',
        categories: 'Categories',
        products: 'Products',
        orders: 'Orders',
        auditlog: 'Audit Log',
        versions: 'Version Control',
    };
    const sectionSubs = {
        access: 'Manage admin accounts and permissions',
        categories: 'Organize equipment into categories',
        products: 'Equipment packages and pricing',
        orders: 'View and manage submitted orders',
        auditlog: 'Full activity log for all admins',
        versions: 'Portal version history — superadmin only',
    };

    return (
        <div className="app-shell">
            <div className="sidebar">
                <div className="sidebar-gold-bar"></div>
                <div className="sidebar-brand">
                    <div className="sidebar-logomark"><img src="data:image/jpeg;base64," alt="FPG" /></div>
                    <div>
                        <div className="sidebar-brand-title">Equipment Admin</div>
                        <div className="sidebar-brand-sub">Foundation Partners Group</div>
                    </div>
                </div>
                <nav className="sidebar-nav">
                    <div className="sidebar-section-label">Main</div>
                    <button className={`sidebar-item ${activeTab==='orders'?'active':''}`} onClick={()=>setActiveTab('orders')}>
                        <i className="ti ti-clipboard-list sidebar-item-icon"></i> Orders
                    </button>
                    <div className="sidebar-section-label">Ordering Portal</div>
                    <button className={`sidebar-item ${activeTab==='categories'?'active':''}`} onClick={()=>setActiveTab('categories')}>
                        <i className="ti ti-tag sidebar-item-icon"></i> Categories
                    </button>
                    <button className={`sidebar-item ${activeTab==='products'?'active':''}`} onClick={()=>setActiveTab('products')}>
                        <i className="ti ti-package sidebar-item-icon"></i> Products
                    </button>
                    <div className="sidebar-section-label">System Settings</div>
                    <button className={`sidebar-item ${activeTab==='access'?'active':''}`} onClick={()=>setActiveTab('access')}>
                        <i className="ti ti-users sidebar-item-icon"></i> Admins
                    </button>
                    <button className={`sidebar-item ${activeTab==='auditlog'?'active':''}`} onClick={()=>setActiveTab('auditlog')}>
                        <i className="ti ti-file-description sidebar-item-icon"></i> Audit Log
                    </button>
                    {isSuperAdmin && (
                        <button className={`sidebar-item ${activeTab==='versions'?'active':''}`} onClick={()=>setActiveTab('versions')}>
                            <i className="ti ti-versions sidebar-item-icon"></i> Version Control
                        </button>
                    )}
                </nav>
                <div className="sidebar-footer">
                    <div className="sidebar-user">
                        <div className="sidebar-avatar">{initials}</div>
                        <div className="sidebar-user-info">
                            <div className="sidebar-user-email">{session.email}</div>
                            <div className="sidebar-user-role">{isSuperAdmin ? 'Superadmin' : 'Admin'}</div>
                        </div>
                        <button className="btn-logout" onClick={onLogout}>→</button>
                    </div>
                </div>
            </div>
            <div className="main-area">
                {inactivityWarning && (
                    <div className="inactivity-bar">
                        ⚠️ You'll be automatically logged out in 10 minutes due to inactivity.
                        <button onClick={() => setInactivityWarning(false)} style={{background:'rgba(255,255,255,0.2)',border:'none',color:'white',padding:'4px 12px',borderRadius:'6px',cursor:'pointer',fontSize:'12px',fontFamily:'inherit'}}>Dismiss</button>
                    </div>
                )}
                <div className="topbar">
                    <div>
                        <div className="topbar-title">{sectionTitles[activeTab] || 'Dashboard'}</div>
                        <div className="topbar-sub">{sectionSubs[activeTab] || ''}</div>
                    </div>
                    <div className="topbar-actions">
                        {activeTab === 'products' && draftCount > 0 && (
                            <button className="btn btn-primary" style={{fontSize:'12px',padding:'6px 14px'}} onClick={() => setShowReviewModal(true)}>
                                {draftCount} Unsaved Change{draftCount !== 1 ? 's' : ''}
                            </button>
                        )}
                    </div>
                </div>

                <div className="main-content">
                <div className="admin-container">

                {activeTab === 'access' && <AccessManagement session={session} azureUrl={AZURE_FUNCTION_URL} adminPortalUrl={ADMIN_PORTAL_URL} />}
                {activeTab === 'categories' && <CategoryManagement session={session} azureUrl={AZURE_FUNCTION_URL} categories={categories} products={products} onCategoryAdded={handleCategoryAdded} onCategoryUpdated={handleCategoryUpdated} onCategoryRemoved={handleCategoryRemoved} />}
                {activeTab === 'orders' && <OrdersDashboard session={session} azureUrl={AZURE_FUNCTION_URL} onNavigate={setActiveTab} />}
                {activeTab === 'auditlog' && <AuditLogOpener session={session} azureUrl={AZURE_FUNCTION_URL} />}
                {activeTab === 'versions' && isSuperAdmin && <VersionControl session={session} azureUrl={AZURE_FUNCTION_URL} />}

                {activeTab === 'products' && <div>
                {draftCount > 0 && (
                    <div className="draft-banner">
                        <div className="draft-info">
                            <span className="draft-icon">⚠️</span>
                            <div className="draft-text">
                                <h3>{draftCount} Unsaved Change{draftCount !== 1 ? 's' : ''}</h3>
                                <p>Changes are saved locally and will survive browser close</p>
                            </div>
                        </div>
                        <div className="draft-actions">
                            <button className="btn-review" onClick={() => setShowReviewModal(true)}>
                                Review Changes
                            </button>
                            <button className="btn-publish-all" onClick={handlePublishAll}>
                                📥 Publish All
                            </button>
                            <button className="btn-clear-drafts" onClick={handleClearDrafts}>
                                Clear All
                            </button>
                        </div>
                    </div>
                )}
                
                <div style={{background:'white',borderRadius:'12px',border:'0.5px solid #E2E8F0',overflow:'hidden',maxWidth:'1200px'}}>
                    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'12px 16px',borderBottom:'0.5px solid #F1F5F9'}}>
                        <div>
                            <span style={{fontSize:'15px',fontWeight:700,color:'#0F172A'}}>Products</span>
                            <span style={{fontSize:'13px',fontWeight:400,color:'#64748B',marginLeft:'8px'}}>{products.length} items</span>
                        </div>
                        <div style={{display:'flex',gap:'8px'}}>
                            {draftCount > 0 && (
                                <button onClick={()=>setShowReviewModal(true)} style={{padding:'7px 14px',background:'white',border:'1.5px solid #E2E8F0',borderRadius:'8px',fontSize:'12px',fontWeight:600,color:'#475569',cursor:'pointer'}}>
                                    {draftCount} unsaved change{draftCount!==1?'s':''}
                                </button>
                            )}
                            <button onClick={()=>{setEditingProduct({title:'',category:'desktop',items:[],price:0,recommended:false,available:true,imageUrl:''});setShowModal(true);}} style={{padding:'7px 16px',background:'linear-gradient(135deg,#15803D,#16A34A)',color:'white',border:'none',borderRadius:'8px',fontSize:'13px',fontWeight:600,cursor:'pointer'}}>
                                + Add Product
                            </button>
                        </div>
                    </div>
                    <table id="tbl-products" className="resizable-table" style={{width:'100%',borderCollapse:'collapse',fontSize:'13px',tableLayout:'fixed'}}>
                        <thead>
                            <tr style={{background:'#D97706'}}>
                                <th style={{padding:'11px 16px',textAlign:'left',color:'white',fontSize:'11px',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.07em',width:'36%',position:'relative'}}>Product</th>
                                <th style={{padding:'11px 16px',textAlign:'left',color:'white',fontSize:'11px',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.07em',width:'16%'}}>Category</th>
                                <th style={{padding:'11px 16px',textAlign:'left',color:'white',fontSize:'11px',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.07em',width:'12%'}}>Price</th>
                                <th style={{padding:'11px 16px',textAlign:'left',color:'white',fontSize:'11px',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.07em',width:'10%'}}>Status</th>
                                <th style={{padding:'11px 16px',textAlign:'right',color:'white',fontSize:'11px',fontWeight:700,textTransform:'uppercase',letterSpacing:'0.07em'}}>Actions</th>
                            </tr>
                        </thead>
                        <tbody>
                            {[...products].sort((a, b) => a.title.localeCompare(b.title)).map((product, idx) => {
                                const isDraft = DraftService.isDraftProduct(product.id);
                                const catLabel = (categories||[]).find(c=>c.slug===product.category);
                                return (
                                    <tr key={product.id} style={{background:isDraft?'#FFFBEB':idx%2===0?'white':'#F9FAFB',borderBottom:'1px solid #F1F5F9'}}>
                                        <td style={{padding:'11px 16px'}}>
                                            <div style={{display:'flex',alignItems:'center',gap:'12px'}}>
                                                <div style={{width:'44px',height:'44px',borderRadius:'8px',overflow:'hidden',flexShrink:0,background:'#F5F3FF',display:'flex',alignItems:'center',justifyContent:'center',border:'1px solid #EDE9FE'}}>
                                                    {product.imageUrl
                                                        ? <img src={product.imageUrl} alt={product.title} style={{width:'100%',height:'100%',objectFit:'cover'}} onError={function(e){e.target.style.display='none';e.target.parentNode.style.display='flex';e.target.parentNode.innerHTML='<i className="ti ti-package" style="font-size:20px;color:#6366F1"></i>';}} />
                                                        : <i className="ti ti-package" style={{fontSize:'20px',color:'#6366F1'}}></i>}
                                                </div>
                                                <div>
                                                    <div style={{fontWeight:600,color:'#0F172A',fontSize:'13px'}}>{product.title}{product.recommended?<span style={{marginLeft:'6px',color:'#F59E0B',fontSize:'12px'}}>★</span>:null}</div>
                                                    {isDraft && <span style={{background:'#FEF3C7',color:'#92400E',padding:'1px 7px',borderRadius:'4px',fontSize:'10px',fontWeight:700,border:'1px solid #FDE68A'}}>EDITED</span>}
                                                </div>
                                            </div>
                                        </td>
                                        <td style={{padding:'11px 16px',color:'#475569',fontSize:'12.5px'}}>{catLabel?catLabel.label:product.category}</td>
                                        <td style={{padding:'11px 16px',fontWeight:700,color:'#4C3BAF',fontSize:'14px',fontFamily:'Georgia,serif'}}>${product.price.toLocaleString()}</td>
                                        <td style={{padding:'11px 16px'}}>
                                            <button className={`status-badge ${product.available?'status-active':'status-inactive'}`} onClick={()=>handleToggleStatus(product.id)} style={{cursor:'pointer',border:'none',fontSize:'10.5px',padding:'3px 10px',borderRadius:'20px',fontWeight:600}}>{product.available?'Published':'Draft'}</button>
                                        </td>
                                        <td style={{padding:'11px 16px',textAlign:'right'}}>
                                            <div style={{display:'flex',gap:'6px',justifyContent:'flex-end'}}>
                                                <button onClick={()=>{setEditingProduct(product);setShowModal(true);}} style={{padding:'5px 14px',border:'1.5px solid #E2E8F0',borderRadius:'7px',fontSize:'11.5px',fontWeight:600,background:'white',color:'#1E3A5F',cursor:'pointer'}}>Edit</button>
                                                <button onClick={()=>handleDelete(product.id)} style={{padding:'5px 14px',border:'1.5px solid #FCA5A5',borderRadius:'7px',fontSize:'11.5px',fontWeight:600,background:'white',color:'#DC2626',cursor:'pointer'}}>Delete</button>
                                            </div>
                                        </td>
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
                </div>}

                </div>
                </div>

                {showModal && (
                    <ProductModal
                        product={editingProduct}
                        categories={categories}
                        onCategoryAdded={handleCategoryAdded}
                        onCategoryRemoved={handleCategoryRemoved}
                        session={session}
                        azureUrl={AZURE_FUNCTION_URL}
                        onSave={handleSave}
                        onClose={() => {
                            setShowModal(false);
                            setEditingProduct(null);
                        }}
                    />
                )}
                
                {showReviewModal && (
                    <ReviewChangesModal
                        drafts={DraftService.getDrafts()}
                        products={products}
                        onClose={() => setShowReviewModal(false)}
                    />
                )}
                
                <ConfirmModal
                    isOpen={showConfirmModal}
                    title="Ready to Publish?"
                    message={`${confirmData.count || 0} product ${confirmData.updates || 'updates'} will be published to the live site.`}
                    detail="Your changes will appear in 2-3 minutes."
                    onConfirm={handleConfirmPublish}
                    onCancel={() => setShowConfirmModal(false)}
                />
                
                <SuccessModal
                    isOpen={showSuccessModal}
                    title="Successfully Published!"
                    message={`${successData.count || 0} products have been published to GitHub.`}
                    detail={successData.commitSha ? `Commit: ${successData.commitSha}\nYour changes will be live in 2-3 minutes.` : "Your changes will be live in 2-3 minutes."}
                    onClose={() => setShowSuccessModal(false)}
                />
            </div>
        </div>
    );
}
